#!/bin/bash
# Script to identify old Docker images that can be safely deleted
# Shows images older than 30 days or beyond the keep limit

PROJECT_ID="flashlive-daily-scraper"
REGION="us-central1"
KEEP_IMAGES=1  # Keep latest 1 image per service (services use SHA256 digests, so old images aren't needed)
DAYS_OLD=30  # Flag images older than this many days

echo "🔍 Identifying Old Docker Images for Cleanup"
echo "Project: $PROJECT_ID"
echo "Keeping: Latest $KEEP_IMAGES images per service"
echo "Flagging: Images older than $DAYS_OLD days"
echo ""

