    echo "📦 Repository: $repo"
    
    # Get all images with timestamps
    local images=$(gcloud artifacts docker images list us-central1-docker.pkg.dev/$PROJECT_ID/$repo --limit=1000 --sort-by=~update_time --format="table(package,tags,create_time,update_time)" 2>&1 | tail -n +2)
    
    if [ -z "$images" ]; then
        echo "  No images found"
        return
    fi
    
    # Group by image base name (without version)
    echo "$images" | while IFS= read -r line; do
        if [ ! -z "$line" ]; then
            echo "  $line"
        fi
    done | head -20
    
    local total=$(echo "$images" | wc -l)
    echo ""
    echo "  Total images: $total"
    
    # Count images beyond keep limit
    local unique_images=$(echo "$images" | awk '{print $1}' | sed 's/@.*$//' | sort -u | wc -l)
    local excess=$((total - (unique_images * KEEP_IMAGES)))
    
    if [ $excess -gt 0 ]; then
        echo "  ⚠️  Can delete: ~$excess old images (beyond keep limit)"
    else
        echo "  ✅ All images within keep limit"
    fi
}

